#!/bin/bash
set -e

echo "=============================================="
echo "  VPS Manager Panel v2.2 - Installation"
echo "=============================================="
echo ""

# Interactive admin password
read -sp "Create admin panel password (min 6 chars): " ADMIN_PASS < /dev/tty
echo ""
if [ -z "$ADMIN_PASS" ] || [ ${#ADMIN_PASS} -lt 6 ]; then
    echo "❌ Password must be at least 6 characters!"
    exit 1
fi
read -sp "Confirm admin password: " ADMIN_CONFIRM < /dev/tty
echo ""
if [ "$ADMIN_PASS" != "$ADMIN_CONFIRM" ]; then
    echo "❌ Passwords do not match!"
    exit 1
fi

echo ""
echo "📦 Installing dependencies..."
apt-get update -qq 2>/dev/null
DEBIAN_FRONTEND=noninteractive apt-get install -y -qq software-properties-common curl unzip nginx mariadb-server phpmyadmin certbot python3-certbot-nginx 2>/dev/null

if ! command -v php8.1 &>/dev/null; then
    add-apt-repository -y ppa:ondrej/php 2>/dev/null
    apt-get update -qq 2>/dev/null
    DEBIAN_FRONTEND=noninteractive apt-get install -y -qq php8.1-fpm php8.1-cli php8.1-mysql php8.1-curl php8.1-gd php8.1-mbstring php8.1-xml php8.1-zip php8.1-intl php8.1-bcmath 2>/dev/null
fi

echo "📁 Setting up panel..."
mkdir -p /var/www/manager/backups /var/www/manager/pma

echo "" | base64 -d | gunzip > /var/www/manager/index.php

echo "$ADMIN_PASS" > /var/www/manager/.passwd
chmod 600 /var/www/manager/.passwd
cat > /var/www/manager/.users << USEREOF
[{"user":"admin","pass":"$ADMIN_PASS","role":"admin"}]
USEREOF
chmod 600 /var/www/manager/.users

[ -d /usr/share/phpmyadmin ] && [ ! -L /var/www/manager/pma ] && ln -sf /usr/share/phpmyadmin /var/www/manager/pma
chown -R www-data:www-data /var/www/manager
systemctl enable --now php8.1-fpm 2>/dev/null

if command -v pm2 &>/dev/null; then
    pm2 stop vps-manager 2>/dev/null || true
    pm2 delete vps-manager 2>/dev/null || true
    pm2 start "php8.1 -S 0.0.0.0:8080 -t /var/www/manager" --name vps-manager
    pm2 save
else
    cat > /etc/systemd/system/vps-manager.service << 'SVC'
[Unit]
Description=VPS Manager Panel
After=network.target
[Service]
Type=simple
User=www-data
ExecStart=/usr/bin/php8.1 -S 0.0.0.0:8080 -t /var/www/manager
Restart=always
RestartSec=5
[Install]
WantedBy=multi-user.target
SVC
    systemctl daemon-reload
    systemctl enable --now vps-manager 2>/dev/null
fi

sleep 2
IP=$(hostname -I | awk '{print $1}')
echo ""
echo "=============================================="
echo "  ✅ VPS Manager Panel v2.2 installed!"
echo "  🌐  http://${IP}:8080"
echo "  👤  Username: admin"
echo "  🔑  Password: (yang barusan kamu buat)"
echo "  ⚡  Next: Login → Services → Install All"
echo "=============================================="
